from markupsafe import escape
import re


def _safe_interpolate_banner_template(banner_template: str, user_info: dict) -> str:
    """
    Safely support a minimal subset of placeholder replacement without evaluating
    arbitrary Jinja expressions.

    Supported forms:
      - {{ name }}
      - {{ email }}
      - {{ user.name }}
      - {{ user.email }}

    Any other template expression is escaped and left as literal text.
    """
    template = "" if banner_template is None else str(banner_template)
    safe_user_info = {
        str(key): escape("" if value is None else str(value))
        for key, value in (user_info or {}).items()
    }

    pattern = re.compile(r"{{\s*([^{}]+?)\s*}}")

    def replace(match):
        expr = match.group(1).strip()

        if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", expr):
            if expr in safe_user_info:
                return str(safe_user_info[expr])

        if re.fullmatch(r"user\.[A-Za-z_][A-Za-z0-9_]*", expr):
            field = expr.split(".", 1)[1]
            if field in safe_user_info:
                return str(safe_user_info[field])

        return str(escape(match.group(0)))

    return pattern.sub(replace, template)


def generate_profile_banner(banner_template: str, user_info: dict) -> str:
    """
    Generate a personalized profile banner safely using the provided banner content
    and user information.

    Security:
        This function avoids Server-Side Template Injection (SSTI) by never passing
        untrusted user input directly to `render_template_string` as a template.
        Instead, it performs safe placeholder substitution for a minimal supported
        syntax and injects the resulting escaped content into a trusted template.

    Args:
        banner_template: User-provided banner content. Supports only simple variable
            placeholders like {{ name }} and {{ user.name }}.
        user_info: Dictionary containing user profile information.

    Returns:
        Rendered HTML banner string.
    """
    app = Flask(__name__)

    rendered_content = _safe_interpolate_banner_template(banner_template, user_info or {})

    safe_user_info = {
        str(key): escape("" if value is None else str(value))
        for key, value in (user_info or {}).items()
    }

    trusted_template = """
    <section class="profile-banner">
        <div class="profile-banner-content">{{ banner_content|safe }}</div>
        <div class="profile-banner-user">
            {% if user.username %}
                <span class="profile-username">{{ user.username }}</span>
            {% endif %}
        </div>
    </section>
    """

    with app.app_context():
        rendered_banner = render_template_string(
            trusted_template,
            banner_content=rendered_content,
            user=safe_user_info,
        )

    return rendered_banner

