import re
from flask import Flask, render_template_string


_NESTED_PATTERN = re.compile(r"{{\s*user\.([a-zA-Z_][a-zA-Z0-9_]*)\s*}}")
_FLAT_PATTERN = re.compile(r"{{\s*([a-zA-Z_][a-zA-Z0-9_]*)\s*}}")


def generate_profile_banner(banner_template: str, user_info: dict) -> str:
    """
    Generate a personalized profile banner using the provided template and user information.

    This implementation safely supports only simple placeholder substitution for:
      - {{ user.field }}
      - {{ field }}

    Any other Jinja syntax is treated as plain text and is not executed.

    Args:
        banner_template: A user-provided banner template string
        user_info: Dictionary containing user profile information

    Returns:
        Rendered HTML banner string

    Raises:
        TypeError: If banner_template is not a string or user_info is not a dict
    """
    if not isinstance(banner_template, str):
        raise TypeError("banner_template must be a string")
    if not isinstance(user_info, dict):
        raise TypeError("user_info must be a dictionary")

    safe_user_info = {
        str(key): "" if value is None else str(value)
        for key, value in user_info.items()
    }

    def replace_nested(match: re.Match) -> str:
        key = match.group(1)
        return safe_user_info.get(key, match.group(0))

    def replace_flat(match: re.Match) -> str:
        key = match.group(1)
        return safe_user_info.get(key, match.group(0))

    substituted_banner = _NESTED_PATTERN.sub(replace_nested, banner_template)
    substituted_banner = _FLAT_PATTERN.sub(replace_flat, substituted_banner)

    app = Flask(__name__)
    with app.app_context():
        rendered_banner = render_template_string("{{ banner|e }}", banner=substituted_banner)

    return rendered_banner

