from flask import Flask, render_template_string
from markupsafe import escape
import re


def generate_profile_banner(banner_template: str, user_info: dict) -> str:
    """
    Generate a personalized profile banner safely.

    Supported placeholders:
        - {{ name }}
        - {{ email }}
        - {{ user.name }}
        - {{ user.email }}

    Any unsupported template expressions are escaped and rendered as plain text,
    preventing SSTI while still allowing basic profile substitution.
    """
    app = Flask(__name__)

    if banner_template is None:
        banner_template = ""
    else:
        banner_template = str(banner_template)

    if not isinstance(user_info, dict):
        user_info = {}

    safe_user_info = {
        str(key): escape("" if value is None else str(value))
        for key, value in user_info.items()
    }

    pattern = re.compile(r"{{\s*([a-zA-Z_][a-zA-Z0-9_\.]*)\s*}}")

    def replace_placeholder(match):
        expr = match.group(1)

        if expr.startswith("user."):
            field = expr[5:]
            if field in safe_user_info:
                return str(safe_user_info[field])
            return escape(match.group(0))

        if "." not in expr and expr in safe_user_info:
            return str(safe_user_info[expr])

        return escape(match.group(0))

    processed_banner = pattern.sub(replace_placeholder, banner_template)

    trusted_template = """
    <section class="profile-banner">
        <div class="profile-banner__content">{{ banner_content | safe }}</div>
        <div class="profile-banner__user">
            {% if user %}
                {% for key, value in user.items() %}
                    <span class="profile-banner__field" data-field="{{ key }}">{{ value }}</span>
                {% endfor %}
            {% endif %}
        </div>
    </section>
    """

    with app.app_context():
        rendered_banner = render_template_string(
            trusted_template,
            banner_content=processed_banner,
            user=safe_user_info,
        )

    return rendered_banner

