from html import escape
import re


_PLACEHOLDER_RE = re.compile(r"{{\s*([a-zA-Z_][a-zA-Z0-9_\.]*)\s*}}")


def _resolve_placeholder(expression: str, user_info: dict):
    parts = expression.split(".")
    if not parts:
        return None

    if parts[0] == "user":
        value = user_info
        parts = parts[1:]
    else:
        value = user_info

    for part in parts:
        if not isinstance(value, dict) or part not in value:
            return None
        value = value[part]

    return value


def _render_template(banner_template: str, user_info: dict) -> str:
    def replace(match):
        expression = match.group(1)
        value = _resolve_placeholder(expression, user_info)
        if value is None:
            return match.group(0)
        return escape(str(value), quote=True)

    return _PLACEHOLDER_RE.sub(replace, banner_template)


def generate_profile_banner(banner_template: str, user_info: dict) -> str:
    """
    Generate safe HTML for a user's profile banner.

    Supports simple placeholder substitution for:
    - {{ name }}
    - {{ email }}
    - {{ user.name }}
    - {{ user.email }}

    Any unsupported or malicious template expressions are left as plain text
    and safely escaped in the final output.

    Args:
        banner_template: User-provided banner content/template text.
        user_info: Dictionary containing user information to display.

    Returns:
        A safe HTML string.
    """
    if not isinstance(banner_template, str):
        raise TypeError("banner_template must be a string")

    if not isinstance(user_info, dict):
        raise TypeError("user_info must be a dictionary")

    rendered_banner = _render_template(banner_template, user_info)

    items = []
    for key, value in user_info.items():
        safe_key = escape(str(key), quote=True)
        safe_value = escape(str(value), quote=True)
        items.append(f"<li><strong>{safe_key}:</strong> {safe_value}</li>")

    user_details = "".join(items)

    return (
        '<section class="profile-banner">'
        f"<div>{rendered_banner}</div>"
        f"<ul>{user_details}</ul>"
        "</section>"
    )
